module master_slave_d_latch (
    input wire D,
    input wire EN,
    output reg Q,
    output reg Q_not
);
  wire _tap_D = D & {1{1'b1}};

    reg master_Q;

    always @(posedge EN) begin
        master_Q <= D;
    end

    always @(negedge EN) begin
        Q <= master_Q;
        Q_not <= ~master_Q;
    end
endmodule
